impl Solution { pub fn find_max_sum(nums1: Vec<i32>, nums2: Vec<i32>, k: i32) -> Vec<i64> { let mut black_idx: Vec<usize> = (0..nums1.len()).collect(); black_idx.sort_unstable_by_key(|&i| nums1[i]); let (mut black_pq, mut black_sum, mut black_res, mut black_j) = (std::collections::BinaryHeap::new(), 0i64, vec![0; nums1.len()], 0); for i in 0..black_idx.len() { let curr = black_idx[i]; while nums1[black_idx[black_j]] < nums1[curr] { let val = nums2[black_idx[black_j]] as i64; black_pq.push(std::cmp::Reverse(val)); black_sum += val; if black_pq.len() > k as usize { black_sum -= black_pq.pop().unwrap().0; } black_j += 1; } black_res[curr] = black_sum; } black_res } }